before_code:
library ieee;
use ieee.std_logic_1164.all;

entity priority_encoder is
  port (
    req : in std_logic_vector(7 downto 0);
    grant : out std_logic_vector(2 downto 0)
  );
end priority_encoder;

architecture rtl of priority_encoder is
begin
  process(req(7))
  begin
    if req(7) = '1' then
      grant <= "111";
    elsif req(6) = '1' then
      grant <= "110";
    elsif req(5) = '1' then
      grant <= "101";
    else
      grant <= "000";
    end if;
  end process;
end rtl;

